

# Datasource credentials
forage.jdbc.username=db_username
forage.jdbc.password=db_password

# S3 access
camel.component.aws2-s3.accessKey=s3_access_key
camel.component.aws2-s3.secretKey=s3_secret_key
camel.component.aws2-s3.uriEndpointOverride=s3_endpoint

# S3 bucket
s3.bucket=s3_bucket

# S3 presigner
s3.presigner.access-key=s3_access_key
s3.presigner.secret-key=s3_secret_key
s3.presigner.uri=s3_endpoint



# Model access
forage.myagent.agent.base.url=maas_url
forage.myagent.agent.api.key=maas_key












# Model access
forage.amend.agent.base.url=maas_url
forage.amend.agent.api.key=maas_key

# Helpdesk credentials
helpdesk.url=helpdesk_url
helpdesk.username=helpdesk_username
helpdesk.password=helpdesk_password
helpdesk.group.id=helpdesk_group_id
helpdesk.type.id.issue=helpdesk_type_id_issue
helpdesk.priority.id.normal=helpdesk_priority_id_normal



# Gold agent - model configuration
forage.profile-gold.agent.base.url=internal_ai_http_route_url
forage.profile-gold.agent.api.key=kuadrant_pro_api_key





# Silver agent - model configuration
forage.profile-silver.agent.base.url=internal_ai_http_route_url
forage.profile-silver.agent.api.key=kuadrant_lite_api_key
